mapper.update:
UPDATE routing.routing_registry
SET routing_status = 'FAILED',
    source_status = 'ERROR',
    last_error_message = #{message},
    last_synced_at = NOW(),
    updated_by = #{updatedBy},
    updated_at = NOW()
WHERE org_key = #{orgKey}
  AND selected_object = #{selectedObject}
  AND routing_protocol = #{routingProtocol}

UPDATE routing.ingestion_slot_registry
SET is_active = FALSE,
    deactivated_at = NOW(),
    updated_at = NOW()
WHERE selected_object = #{selectedObject}
  AND routing_protocol = #{routingProtocol}
